import React from 'react';

const ContactoPage = () => {
  return (
    <main style={styles.page}>
      <header style={styles.header}>
        <div style={styles.line} />
        <h2 style={styles.subtitle}>EMPRESAS QUE FORJARON EL PAIS</h2>
        <div style={styles.line} />
      </header>

      <section style={styles.contentBox}>
        <h1 style={styles.title}>SEMANA DE ACTIVIDADES</h1>
        <p style={styles.description}>
          Explora las últimas noticias, actualizaciones y promociones disponibles en nuestra plataforma.
        </p>
      </section>
    </main>
  );
};

const styles = {
  page: {
    backgroundColor: '#F5EEE2',
    minHeight: '100vh',
    padding: '4rem 2rem',
    fontFamily: "'Montserrat', sans-serif",
    color: '#032F27',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
  },
  header: {
    display: 'flex',
    alignItems: 'center',
    gap: '1rem',
    marginBottom: '2rem',
    width: '100%',
    maxWidth: 900,
    justifyContent: 'center',
  },
  line: {
    flex: 1,
    height: 3,
    backgroundImage: 'repeating-linear-gradient(90deg, #032F27, #032F27 10px, transparent 10px, transparent 20px)',
    borderRadius: 2,
  },
  subtitle: {
    fontSize: '1rem',
    fontWeight: '600',
    letterSpacing: '0.35em',
    textTransform: 'uppercase',
    color: '#032F27',
    whiteSpace: 'nowrap',
  },
  contentBox: {
    backgroundColor: '#FDF8F0',
    padding: '3rem 4rem',
    borderRadius: '30px',
    boxShadow: '0 10px 20px rgba(3,47,39,0.1)',
    maxWidth: 900,
    textAlign: 'center',
  },
  title: {
    fontSize: '2.5rem',
    fontWeight: '700',
    marginBottom: '1.5rem',
  },
  description: {
    fontSize: '1.15rem',
    lineHeight: 1.6,
    maxWidth: 600,
    margin: '0 auto',
    color: '#032F27',
  },
};

export default ContactoPage;
